// frontend/src/components/CheckoutModal.js
import React, { useState } from 'react';

export default function CheckoutModal({ placeName, onSubmit, onClose }) {
  const [amount, setAmount] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (skipCost = false) => {
    setLoading(true);
    await onSubmit(skipCost ? null : amount ? parseFloat(amount) : null);
    setLoading(false);
  };

  return (
    <div
      onClick={e => e.target === e.currentTarget && onClose()}
      style={{
        position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        zIndex: 1000, padding: '20px', backdropFilter: 'blur(4px)',
      }}
    >
      <div style={{
        background: '#fff', borderRadius: '24px', padding: '32px',
        width: '100%', maxWidth: '380px',
        boxShadow: '0 20px 60px rgba(0,0,0,0.2)',
        animation: 'slideUp .3s ease',
      }}>
        <style>{`@keyframes slideUp { from { opacity:0; transform:translateY(20px); } to { opacity:1; transform:translateY(0); } }`}</style>

        <div style={{ textAlign: 'center', marginBottom: '24px' }}>
          <div style={{ fontSize: '40px', marginBottom: '10px' }}>💰</div>
          <h2 style={{ fontSize: '20px', fontWeight: '800', color: '#1a1a2e', margin: '0 0 6px' }}>
            How Much Did You Spend?
          </h2>
          <p style={{ fontSize: '13px', color: '#999', margin: 0 }}>
            At <strong style={{ color: '#1D9E75' }}>{placeName}</strong> — your data helps others plan better
          </p>
        </div>

        {/* Amount input */}
        <div style={{
          display: 'flex', alignItems: 'center', gap: '12px',
          background: '#f7f8fc', borderRadius: '16px', padding: '14px 18px',
          marginBottom: '16px', border: '2px solid #f0f0f0',
        }}>
          <span style={{ fontSize: '22px', fontWeight: '800', color: '#1D9E75' }}>₹</span>
          <input
            type="number" placeholder="0" value={amount} min="0"
            onChange={e => setAmount(e.target.value)}
            autoFocus
            style={{
              flex: 1, border: 'none', background: 'transparent',
              fontSize: '24px', fontWeight: '700', color: '#1a1a2e',
              outline: 'none', textAlign: 'center',
            }}
          />
        </div>

        {/* Quick amounts */}
        <div style={{ display: 'flex', gap: '8px', marginBottom: '24px' }}>
          {[100, 250, 500, 1000].map(v => (
            <button key={v} onClick={() => setAmount(String(v))} style={{
              flex: 1, padding: '9px 4px', border: '1.5px solid',
              borderColor: amount == v ? '#1D9E75' : '#e8e8e8',
              borderRadius: '10px', fontSize: '13px', fontWeight: '600',
              background: amount == v ? '#e8f8f2' : '#fff',
              color: amount == v ? '#0f6e56' : '#888', cursor: 'pointer',
            }}>₹{v}</button>
          ))}
        </div>

        <p style={{ fontSize: '11px', color: '#ccc', textAlign: 'center', marginBottom: '20px' }}>
          Your data is shared anonymously to improve predictions for everyone
        </p>

        <div style={{ display: 'flex', gap: '10px' }}>
          <button onClick={() => handleSubmit(true)} disabled={loading} style={{
            flex: 1, padding: '13px', border: '1.5px solid #e8e8e8',
            background: '#fff', color: '#888', borderRadius: '12px',
            fontSize: '14px', fontWeight: '600', cursor: 'pointer',
          }}>Skip</button>
          <button onClick={() => handleSubmit(false)} disabled={loading} style={{
            flex: 2, padding: '13px',
            background: 'linear-gradient(135deg, #1D9E75, #0f6e56)',
            color: '#fff', border: 'none', borderRadius: '12px',
            fontSize: '14px', fontWeight: '700', cursor: 'pointer',
          }}>{loading ? 'Saving...' : 'Submit ✓'}</button>
        </div>
      </div>
    </div>
  );
}
